class Solution:
    def maxVowels(self, s: str, k: int) -> int:
        vowels = {'a', 'e', 'i', 'o', 'u'}
        n = len(s)
        current = 0
        max_count = 0

        # Initialize the first window
        for i in range(k):
            if s[i] in vowels:
                current += 1
        max_count = current

        # Slide the window
        for i in range(k, n):
            # Remove the leftmost character
            left_char = s[i - k]
            if left_char in vowels:
                current -= 1
            # Add the new right character
            right_char = s[i]
            if right_char in vowels:
                current += 1
            # Update max
            if current > max_count:
                max_count = current

        return max_count

